import 'package:baseball_detector_flutter/data/models/ai_coach/ai_coach_report.dart';
import 'package:flutter/material.dart';

// Package imports:
import 'package:gap/gap.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/player.dart';
import 'package:baseball_detector_flutter/data/models/session.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/components/action_plans_expansion_tile.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/components/count_strategy_expansion_tile.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/components/empty_container.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/components/lefty_strategy_expansion_tile.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/components/new_pitch_expansion_tile.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/components/pitch_features_expansion_tile.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/components/pitch_zones_expansion_tile.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/components/pros_cons_expansion_tile.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/components/regenerate_report_content.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/components/report_generation_status_content.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/ai_coach_report/components/strikeout_strategy_expansion_tile.dart';

class AICoachReportContainer extends HookConsumerWidget {
  const AICoachReportContainer({
    required this.teamId,
    required this.sessionId,
    required this.player,
    this.report,
    this.onSessionUpdated,
    super.key,
  });

  final String teamId;
  final String sessionId;
  final Player? player;
  final AICoachReport? report;
  final void Function(Session updatedSession)? onSessionUpdated;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final theme = Theme.of(context);
    final colorScheme = theme.colorScheme;
    final sectionTitleStyle = theme.textTheme.titleMedium?.copyWith(
      fontWeight: FontWeight.w600,
      color: colorScheme.onSurface,
    );
    final sectionSubtitleStyle = theme.textTheme.bodySmall?.copyWith(
      color: colorScheme.onSurfaceVariant,
    );

    if (report == null) {
      return EmptyContainer(
        teamId: teamId,
        sessionId: sessionId,
        player: player,
        onSessionUpdated: onSessionUpdated,
      );
    }

    final generationState = report!.status;

    if (generationState == AICoachReportStatus.failed) {
      return ReportGenerationStatusContent(
        teamId: teamId,
        sessionId: sessionId,
        player: player,
        title: context.l10n.ai_coach_report__generation_failed_title,
        description:
            context.l10n.ai_coach_report__generation_failed_description,
        buttonLabel: context.l10n.ai_coach_report__generation_retry_button,
        onSessionUpdated: onSessionUpdated,
      );
    }

    if (generationState == AICoachReportStatus.cancelled) {
      return ReportGenerationStatusContent(
        teamId: teamId,
        sessionId: sessionId,
        player: player,
        title: context.l10n.ai_coach_report__generation_canceled_title,
        description:
            context.l10n.ai_coach_report__generation_canceled_description,
        buttonLabel: context.l10n.ai_coach_report__generation_restart_button,
        onSessionUpdated: onSessionUpdated,
      );
    }

    if (generationState == AICoachReportStatus.accepted) {
      return const _ReportGenerationProcessingView();
    }

    if (generationState == AICoachReportStatus.completed &&
        report?.content == null) {
      return ReportGenerationStatusContent(
        teamId: teamId,
        sessionId: sessionId,
        player: player,
        title: context.l10n.ai_coach_report__generation_failed_title,
        description:
            context.l10n.ai_coach_report__generation_failed_description,
        buttonLabel: context.l10n.ai_coach_report__generation_retry_button,
        onSessionUpdated: onSessionUpdated,
      );
    }

    final content = report!.content!;

    return SingleChildScrollView(
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          if (content.pitchFeatures != null) ...[
            PitchFeaturesExpansionTile(
              pitchFeatures: content.pitchFeatures!,
              params: report!.params,
              titleStyle: sectionTitleStyle,
            ),
            const Gap(8),
          ],
          if (content.prosCons != null) ...[
            ProsConsExpansionTile(
              prosCons: content.prosCons!,
              titleStyle: sectionTitleStyle,
              subtitleStyle: sectionSubtitleStyle,
            ),
            const Gap(8),
          ],
          if (content.countRecommendations != null) ...[
            CountStrategyExpansionTile(
              entries: content.countRecommendations!,
              titleStyle: sectionTitleStyle,
              subtitleStyle: sectionSubtitleStyle,
            ),
            const Gap(8),
          ],
          if (content.strikeoutStrategies != null) ...[
            StrikeoutStrategyExpansionTile(
              strategies: content.strikeoutStrategies!,
              titleStyle: sectionTitleStyle,
              subtitleStyle: sectionSubtitleStyle,
            ),
            const Gap(8),
          ],
          if (content.leftyStrategies != null) ...[
            LeftyStrategyExpansionTile(
              strategies: content.leftyStrategies!,
              titleStyle: sectionTitleStyle,
              subtitleStyle: sectionSubtitleStyle,
            ),
            const Gap(8),
          ],
          if (content.pitchZones != null) ...[
            PitchZonesExpansionTile(
              items: content.pitchZones!,
              titleStyle: sectionTitleStyle,
              subtitleStyle: sectionSubtitleStyle,
            ),
            const Gap(8),
          ],
          if (content.newPitches != null) ...[
            NewPitchExpansionTile(
              proposals: content.newPitches!,
              params: report!.params,
            ),
            const Gap(8),
          ],
          if (content.actionPlans != null) ...[
            ActionPlansExpansionTile(
              items: content.actionPlans!,
              titleStyle: sectionTitleStyle,
              subtitleStyle: sectionSubtitleStyle,
            ),
            const Gap(8),
          ],
          const Gap(24),
          RegenerateReportContent(
            teamId: teamId,
            sessionId: sessionId,
            player: player,
            onSessionUpdated: onSessionUpdated,
          ),
          const Gap(24),
        ],
      ),
    );
  }
}

class _ReportGenerationProcessingView extends StatelessWidget {
  const _ReportGenerationProcessingView();

  @override
  Widget build(BuildContext context) {
    final theme = Theme.of(context);
    final colorScheme = theme.colorScheme;

    return LayoutBuilder(
      builder: (context, constraints) {
        return SingleChildScrollView(
          physics: const AlwaysScrollableScrollPhysics(),
          child: ConstrainedBox(
            constraints: BoxConstraints(minHeight: constraints.maxHeight),
            child: Center(
              child: Padding(
                padding: const EdgeInsets.all(24),
                child: ConstrainedBox(
                  constraints: const BoxConstraints(maxWidth: 360),
                  child: Column(
                    mainAxisSize: MainAxisSize.min,
                    children: [
                      Icon(
                        Icons.autorenew_rounded,
                        size: 36,
                        color: colorScheme.primary,
                      ),
                      const Gap(16),
                      Text(
                        context.l10n.ai_coach_report__processing_title,
                        style: theme.textTheme.titleMedium?.copyWith(
                          fontWeight: FontWeight.w600,
                          color: colorScheme.onSurface,
                        ),
                        textAlign: TextAlign.center,
                      ),
                      const Gap(8),
                      Text(
                        context.l10n.ai_coach_report__processing_description,
                        style: theme.textTheme.bodyMedium?.copyWith(
                          color: colorScheme.onSurfaceVariant,
                        ),
                        textAlign: TextAlign.center,
                      ),
                    ],
                  ),
                ),
              ),
            ),
          ),
        );
      },
    );
  }
}

