class ExpansionTileCard extends HookConsumerWidget {
  const ExpansionTileCard({
    required this.titleBuilder,
    required this.children,
    super.key,
  });

  final Widget Function(Widget icon) titleBuilder;
  final List<Widget> children;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final controller = useExpansibleController();

    return Card(
      child: Padding(
        padding: const EdgeInsets.all(12),
        child: ExpansionTile(
          initiallyExpanded: true,
          controller: controller,
          shape: const Border(),
          tilePadding: EdgeInsets.zero,
          childrenPadding: EdgeInsets.zero,
          maintainState: true,
          showTrailingIcon: false,
          title: titleBuilder(
            AnimatedBuilder(
              animation: controller,
              builder: (_, __) => Icon(
                controller.isExpanded
                    ? Icons.keyboard_arrow_up
                    : Icons.keyboard_arrow_down,
              ),
            ),
          ),
          children: [
            const Gap(16),
            GestureDetector(
              onTap: controller.collapse,
              child: LayoutBuilder(
                builder: (context, c) {
                  return Wrap(
                    spacing: 16,
                    runSpacing: 16,
                    children: children,
                  );
                },
              ),
            ),
          ],
        ),
      ),
    );
  }
}

