import 'package:flutter/material.dart';

// Package imports:
import 'package:gap/gap.dart';

const EdgeInsets sectionContainerPadding = EdgeInsets.all(16);

BoxDecoration sectionContainerDecoration(ColorScheme scheme) => BoxDecoration(
      color: scheme.surfaceContainerLow.withValues(alpha: 0.5),
      borderRadius: BorderRadius.circular(4),
      border: Border.all(
        color: scheme.outlineVariant.withValues(alpha: 0.4),
      ),
    );

class StrategyList extends StatelessWidget {
  const StrategyList({
    required this.items,
    super.key,
  });
  final List<(String, String)> items;
  @override
  Widget build(BuildContext context) {
    final scheme = Theme.of(context).colorScheme;
    final textTheme = Theme.of(context).textTheme;
    final containerDecoration = sectionContainerDecoration(scheme);
    final innerPadding = const EdgeInsets.symmetric(vertical: 4);

    return SizedBox(
      width: double.infinity,
      child: DecoratedBox(
        decoration: containerDecoration,
        child: Padding(
          padding: sectionContainerPadding,
          child: Row(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Expanded(
                child: Container(
                  decoration: BoxDecoration(
                    borderRadius: BorderRadius.circular(12),
                  ),
                  padding: innerPadding,
                  child: Column(
                    children: [
                      for (var i = 0; i < items.length; i++) ...[
                        Row(
                          crossAxisAlignment: CrossAxisAlignment.start,
                          children: [
                            Text(
                              '${i + 1}.',
                              style: const TextStyle(
                                fontSize: 16,
                                fontWeight: FontWeight.w700,
                              ),
                            ),
                            const Gap(8),
                            Flexible(
                              child: Text(
                                items[i].$1,
                                style: const TextStyle(
                                  fontSize: 16,
                                  fontWeight: FontWeight.w700,
                                ),
                                maxLines: 100,
                                overflow: TextOverflow.ellipsis,
                                softWrap: true,
                              ),
                            ),
                          ],
                        ),
                        const Gap(6),
                        Align(
                          alignment: Alignment.centerLeft,
                          child: Text(
                            items[i].$2,
                            style: textTheme.bodyMedium?.copyWith(
                              color: scheme.onSurfaceVariant,
                            ),
                          ),
                        ),
                        if (i != items.length - 1) const Gap(16),
                      ],
                    ],
                  ),
                ),
              ),
            ],
          ),
        ),
      ),
    );
  }
}

