class PitchTypeChip extends HookConsumerWidget {
  const PitchTypeChip({
    super.key,
    required this.pitchType,
  });

  final PitchType pitchType;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final theme = Theme.of(context);
    final scheme = theme.colorScheme;
    final translatePitchType = useTranslatePitchType();
    final pitchTypeColor = usePitchTypeColor();

    return Row(
      children: [
        Container(
          width: 6,
          height: 24,
          decoration: BoxDecoration(
            color: pitchTypeColor(pitchType.pitchType),
            borderRadius: BorderRadius.circular(999),
          ),
        ),
        const Gap(8),
        Text(
          translatePitchType(pitchType.pitchType),
          style: theme.textTheme.titleSmall?.copyWith(
            fontWeight: FontWeight.w600,
            color: scheme.onSurface,
          ),
        ),
      ],
    );
  }
}

// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:gap/gap.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/ball.dart' show Ball;
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/utils/snack_bar.dart';
import 'package:baseball_detector_flutter/views/components/custom_button.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/components/all_balls_container.dart';

class RequestReportContent extends HookConsumerWidget {
  const RequestReportContent({
    required this.teamId,
    required this.sessionId,
    super.key,
  });

  final String teamId;
  final String sessionId;

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    // TODO: レポートが生成中であれば生成できないようにする
    final theme = Theme.of(context);
    final colorScheme = theme.colorScheme;

    return AllBallsContainer(
      teamId: teamId,
      sessionId: sessionId,
      builder: ({
        required List<Ball> hittingBalls,
        required List<Ball> pitchingBalls,
      }) {
        final hasPitchingBalls = pitchingBalls.isNotEmpty;
        final hasAllPitchTypes = hasPitchingBalls &&
            !pitchingBalls.any(
              (ball) =>
                  ball.pitchType == null || ball.pitchType?.pitchType == 'none',
            );

        Future<void> requestReport() async {
          if (!hasPitchingBalls) {
            context.showErrorSnackBar(
              context.l10n.ai_coach_report__request_need_pitching_data,
            );
            return;
          }

          if (!hasAllPitchTypes) {
            context.showErrorSnackBar(
              context.l10n.ai_coach_report__request_need_pitch_type,
            );
            return;
          }

          // TODO: サーバー側にリクエストする
          context.showSuccessSnackBar(
            context.l10n.ai_coach_report__request_success_message,
          );
        }

        return Container(
          padding: const EdgeInsets.all(16),
          decoration: BoxDecoration(
            borderRadius: BorderRadius.circular(16),
            border: Border.all(color: colorScheme.outlineVariant),
            color: colorScheme.surface,
          ),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Row(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  _IconBadge(
                      icon: Icons.auto_fix_high, color: colorScheme.primary),
                  const Gap(12),
                  Expanded(
                    child: Column(
                      crossAxisAlignment: CrossAxisAlignment.start,
                      children: [
                        Text(
                          context.l10n.ai_coach_report__request_card_title,
                          style: theme.textTheme.titleMedium?.copyWith(
                            fontWeight: FontWeight.w600,
                          ),
                        ),
                        const Gap(4),
                        Text(
                          context
                              .l10n.ai_coach_report__request_card_description,
                          style: theme.textTheme.bodyMedium?.copyWith(
                            color: colorScheme.onSurfaceVariant,
                          ),
                        ),
                      ],
                    ),
                  ),
                ],
              ),
              const Gap(20),
              _RequirementStatusRow(
                icon: hasPitchingBalls
                    ? Icons.check_circle_rounded
                    : Icons.radio_button_unchecked,
                iconColor: hasPitchingBalls
                    ? colorScheme.primary
                    : colorScheme.outline,
                label: context
                    .l10n.ai_coach_report__request_requirement_pitching_data,
                emphasized: hasPitchingBalls,
              ),
              const Gap(12),
              _RequirementStatusRow(
                icon: hasAllPitchTypes
                    ? Icons.check_circle_rounded
                    : Icons.radio_button_unchecked,
                iconColor: hasAllPitchTypes
                    ? colorScheme.primary
                    : colorScheme.outline,
                label: context
                    .l10n.ai_coach_report__request_requirement_pitch_type,
                emphasized: hasAllPitchTypes,
              ),
              const Gap(20),
              SizedBox(
                width: double.infinity,
                child: CustomButton(
                  text: context.l10n.ai_coach_report__request_button_label,
                  onPressed: requestReport,
                ),
              ),
            ],
          ),
        );
      },
    );
  }
}

class _IconBadge extends StatelessWidget {
  const _IconBadge({
    required this.icon,
    required this.color,
  });

  final IconData icon;
  final Color color;

  @override
  Widget build(BuildContext context) {
    return Container(
      height: 40,
      width: 40,
      decoration: BoxDecoration(
        color: color.withValues(alpha: 0.12),
        borderRadius: BorderRadius.circular(12),
      ),
      child: Icon(icon, color: color),
    );
  }
}

class _RequirementStatusRow extends StatelessWidget {
  const _RequirementStatusRow({
    required this.icon,
    required this.iconColor,
    required this.label,
    required this.emphasized,
  });

  final IconData icon;
  final Color iconColor;
  final String label;
  final bool emphasized;

  @override
  Widget build(BuildContext context) {
    final theme = Theme.of(context);
    final colorScheme = theme.colorScheme;

    return Row(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Icon(icon, color: iconColor, size: 20),
        const Gap(12),
        Expanded(
          child: Text(
            label,
            style: theme.textTheme.bodyMedium?.copyWith(
              color: emphasized
                  ? colorScheme.onSurface
                  : colorScheme.onSurfaceVariant,
              fontWeight: emphasized ? FontWeight.w600 : FontWeight.w400,
            ),
          ),
        ),
      ],
    );
  }
}

